      var ic = add(row, "div"); ic.style.cssText = "font-size:20px;line-height:1.2;flex:0 0 auto;"; ic.innerHTML = '<i class="ti ' + t.icon + '"></i>';
      var txt = add(row, "div"); txt.style.cssText = "flex:1;min-width:0;";
